mapper.select:
/* PrdtMngMapper.prdtMngList */ SELECT PRDT_ID , MAKER , PRDT_NM , PRDT_DESC , OUT_UNIT_PRIC , USE_YN , IMG_FILE , WEB_URL , FN_GET_USRNM(A.RVISN_ID) AS USR_NM FROM MSP_GIFT_PRDT A WHERE 1=1
AND A.PRDT_ID = #{prdtId, jdbcType=VARCHAR}
AND A.MAKER = #{maker, jdbcType=VARCHAR}
AND A.PRDT_NM LIKE '%' || #{prdtNm, jdbcType=VARCHAR} || '%'
AND A.USE_YN = #{useYn, jdbcType=VARCHAR}
ORDER BY A.PRDT_ID, A.MAKER, A.PRDT_NM

/* UsimPrdtMngMapper.usimPrdtMngHist */ SELECT PRDT_ID , MAKER , PRDT_NM , PRDT_DESC , OUT_UNIT_PRIC , OUT_UNIT_PRIC * 1.1 OUT_UNIT_PRIC_VAT , USE_YN , IMG_FILE , WEB_URL , FN_GET_USRNM(A.RVISN_ID) AS USR_NM , TO_CHAR(RVISN_DTTM,'YYYY-MM-DD HH24:MI:SS') RVISN_DTTM FROM MSP_GIFT_PRDT_HIST A WHERE 1=1
AND A.PRDT_ID = #{prdtId, jdbcType=VARCHAR}
ORDER BY A.SEQ DESC

