UPDATE  MSP_GIFT_PRDT
   SET  MAKER = #{maker, jdbcType=VARCHAR}
      , PRDT_NM = #{prdtNm, jdbcType=VARCHAR}
      , PRDT_DESC = #{prdtDesc, jdbcType=VARCHAR}
      , OUT_UNIT_PRIC = #{outUnitPric, jdbcType=VARCHAR}
      , USE_YN = #{useYn, jdbcType=VARCHAR}
      , IMG_FILE = #{imgFile, jdbcType=VARCHAR}
      , WEB_URL = #{webUrl, jdbcType=VARCHAR}
      , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
