SELECT /* PrdtMngMapper.getImageFile */ ATT_ROUT /* 파일경로 */ , FILE_NM /* 파일명 */ , FILE_ID /* 파일ID */ FROM ORG_FILE_MGMT_MST OFMM WHERE OFMM.ATT_SCTN = 'GIT'
AND OFMM.ORGN_ID = #{prdtId, jdbcType=VARCHAR}
AND OFMM.FILE_ID = #{fileId1, jdbcType=VARCHAR}
ORDER BY OFMM.REG_DTTM
